package tests.panels.arming;

import base.TestBase;
import org.testng.annotations.Test;

// EX-T1003
public class DismissAlertTest extends TestBase {

    @Test(groups = {"dismiss-alert", "group-01"})
    public void testDismissAlertFromApp() {
        // Step 1: Trigger a door/window sensor alarm
        REPORT("Door/window sensor triggers an alarm");
        sensor.triggerAlarm(SensorType.DOOR_WINDOW);
        panel.assertState(PanelState.ALARM_ACTIVE);

        // Step 2: App displays active alarm notification
        REPORT("Mobile app displays active alarm notification");
        mobileApp.assertAlarmNotificationVisible();

        // Step 3: User dismisses alert from app
        REPORT("User dismisses alert from mobile app");
        mobileApp.dismissAlert(config.getMasterCode());

        // Step 4: Panel returns to ARMED STAY state
        REPORT("Panel returns to ARMED STAY after dismissal");
        panel.assertState(PanelState.ARMED_STAY);

        // Step 5: App confirms alert dismissed
        REPORT("Mobile app confirms alert is dismissed");
        mobileApp.assertAlarmNotificationGone();

        // Cleanup
        panel.disarm(config.getMasterCode());
    }
}
